mapper.select:
SELECT
    ${tableSpec.orderIdSelect},
    ${tableSpec.orderNoSelect},
    ${tableSpec.orderStatusSelect},
    ${tableSpec.payStatusSelect},
    ${tableSpec.orderTimeSelect},
    ${tableSpec.payTimeSelect},
    ${tableSpec.totalAmountSelect},
    ${tableSpec.buyerNicknameSelect}
FROM ${tableSpec.tableName}
WHERE ${tableSpec.orderTimeColumn} >= #{startTime}
  AND ${tableSpec.orderTimeColumn} < #{endTime}

    AND ${tableSpec.orderNoColumn} LIKE CONCAT('%', #{keyword}, '%')

ORDER BY ${tableSpec.orderTimeColumn} DESC
LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(1)
FROM ${tableSpec.tableName}
WHERE ${tableSpec.orderTimeColumn} >= #{startTime}
  AND ${tableSpec.orderTimeColumn} < #{endTime}

    AND ${tableSpec.orderNoColumn} LIKE CONCAT('%', #{keyword}, '%')

SELECT
    CAST(${tableSpec.statDateColumn} AS CHAR) AS statDate,
    COALESCE(SUM(${tableSpec.orderCountExpression}), 0) AS orderCount,
    COALESCE(SUM(${tableSpec.paidOrderCountExpression}), 0) AS paidOrderCount,
    COALESCE(SUM(${tableSpec.totalAmountExpression}), 0) AS totalAmount,
    COALESCE(SUM(${tableSpec.paidAmountExpression}), 0) AS paidAmount,
    COALESCE(SUM(${tableSpec.refundAmountExpression}), 0) AS refundAmount
FROM ${tableSpec.tableName}
WHERE ${tableSpec.statDateColumn} >= #{startDate}
  AND ${tableSpec.statDateColumn} <= #{endDate}
GROUP BY ${tableSpec.statDateColumn}
ORDER BY ${tableSpec.statDateColumn} ASC

SELECT CAST(MAX(${tableSpec.statDateColumn}) AS CHAR) AS latestStatDate, COALESCE(SUM(${tableSpec.orderCountExpression}), 0) AS orderCount, COALESCE(SUM(${tableSpec.paidOrderCountExpression}), 0) AS paidOrderCount, COALESCE(SUM(${tableSpec.unpaidOrderCountExpression}), 0) AS unpaidOrderCount, COALESCE(SUM(${tableSpec.closedOrderCountExpression}), 0) AS closedOrderCount, COALESCE(SUM(${tableSpec.totalAmountExpression}), 0) AS totalAmount, COALESCE(SUM(${tableSpec.paidAmountExpression}), 0) AS paidAmount, COALESCE(SUM(${tableSpec.refundAmountExpression}), 0) AS refundAmount, CASE WHEN COALESCE(SUM(${tableSpec.orderCountExpression}), 0) = 0 THEN 0 ELSE ROUND( CAST(COALESCE(SUM(${tableSpec.paidOrderCountExpression}), 0) AS DECIMAL(18, 4)) / COALESCE(SUM(${tableSpec.orderCountExpression}), 0), 4 ) END AS paySuccessRate FROM ${tableSpec.tableName}
${tableSpec.statDateColumn} >= #{startDate}
AND
${tableSpec.statDateColumn} <= #{endDate}

SELECT CAST(log_id AS CHAR) AS logId, CAST(job_code AS CHAR) AS jobCode, CAST(job_name AS CHAR) AS jobName, CAST(run_status AS CHAR) AS runStatus, CAST(message AS CHAR) AS message, synced_order_count AS syncedOrderCount, synced_payment_order_count AS syncedPaymentOrderCount, synced_notify_log_count AS syncedNotifyLogCount, started_at AS startedAt, finished_at AS finishedAt, duration_ms AS durationMs, created_at AS createdAt FROM dw_sync_job_log
WHERE job_code = #{jobCode}
ORDER BY started_at DESC LIMIT #{limit}

SELECT CAST(table_code AS CHAR) AS tableCode, CAST(datasource_code AS CHAR) AS datasourceCode, CAST(table_name AS CHAR) AS tableName, CAST(table_layer AS CHAR) AS tableLayer, CAST(table_category AS CHAR) AS tableCategory, CAST(table_comment AS CHAR) AS tableComment, CAST(owner AS CHAR) AS owner, CAST(refresh_strategy AS CHAR) AS refreshStrategy, column_count AS columnCount FROM dw_meta_table
datasource_code = #{datasourceCode}
AND
table_layer = #{tableLayer}
ORDER BY table_layer ASC, table_name ASC LIMIT #{limit}

SELECT CAST(relation_id AS CHAR) AS relationId, CAST(relation_type AS CHAR) AS relationType, CAST(upstream_datasource_code AS CHAR) AS upstreamDatasourceCode, CAST(upstream_table_code AS CHAR) AS upstreamTableCode, CAST(downstream_datasource_code AS CHAR) AS downstreamDatasourceCode, CAST(downstream_table_code AS CHAR) AS downstreamTableCode, CAST(transform_name AS CHAR) AS transformName, enabled AS enabled FROM dw_lineage_relation
upstream_table_code = #{tableCode} OR downstream_table_code = #{tableCode}
ORDER BY upstream_table_code ASC, downstream_table_code ASC LIMIT #{limit}

SELECT CAST(alert_id AS CHAR) AS alertId, CAST(alert_type AS CHAR) AS alertType, CAST(alert_level AS CHAR) AS alertLevel, CAST(alert_source AS CHAR) AS alertSource, CAST(source_code AS CHAR) AS sourceCode, CAST(source_name AS CHAR) AS sourceName, CAST(alert_status AS CHAR) AS alertStatus, CAST(alert_title AS CHAR) AS alertTitle, CAST(alert_message AS CHAR) AS alertMessage, CAST(fired_at AS CHAR) AS firedAt, CAST(resolved_at AS CHAR) AS resolvedAt FROM dw_alert_record
WHERE alert_status = #{alertStatus}
ORDER BY fired_at DESC, created_at DESC LIMIT #{limit}

SELECT CAST(log_id AS CHAR) AS logId, CAST(job_code AS CHAR) AS jobCode, CAST(job_name AS CHAR) AS jobName, CAST(job_type AS CHAR) AS jobType, CAST(source_type AS CHAR) AS sourceType, CAST(source_tables AS CHAR) AS sourceTables, CAST(target_tables AS CHAR) AS targetTables, CAST(run_status AS CHAR) AS runStatus, CAST(message AS CHAR) AS message, CAST(metric_one_label AS CHAR) AS metricOneLabel, metric_one_value AS metricOneValue, CAST(metric_two_label AS CHAR) AS metricTwoLabel, metric_two_value AS metricTwoValue, CAST(metric_three_label AS CHAR) AS metricThreeLabel, metric_three_value AS metricThreeValue, CAST(started_at AS CHAR) AS startedAt, CAST(finished_at AS CHAR) AS finishedAt, duration_ms AS durationMs FROM dw_job_log
WHERE job_code = #{jobCode}
ORDER BY started_at DESC LIMIT #{limit}
